1	/**
2	 * Bill Validator API Route
3	 *
4	 * This route handles fetching bill validator data for a specific machine.
5	 * It supports:
6	 * - V1 and V2 data format handling
7	 * - Gaming day offset calculations
8	 * - Time period filtering
9	 * - Custom date range filtering
10	 * - Bill denomination filtering based on location settings
11	 *
12	 * @module app/api/bill-validator/[machineId]/route
13	 */
14	
15	import { connectDB } from '@/app/api/lib/middleware/db';
16	import { AcceptedBill } from '@/app/api/lib/models/acceptedBills';
17	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
18	import { Machine } from '@/app/api/lib/models/machines';
19	import type { TimePeriod } from '@/shared/types/common';
20	import {
21	  processBillsData,
22	  createDateFilter,
23	  DEFAULT_BILL_VALIDATOR_OPTIONS,
24	  type BillDocument,
25	} from '@/app/api/lib/helpers/billValidator/validatorOperations';
26	import {
27	  logRouteFetch,
28	  logRouteError,
29	  extractUserFromRequest,
30	} from '@/app/api/lib/utils/routeLogger';
31	import { NextRequest, NextResponse } from 'next/server';
32	
33	/**
34	 * GET /api/bill-validator/[machineId]
35	 *
36	 * Returns denomination-level bill validator data (counts, subtotals, and totals)
37	 * for a single machine, filtered by time period or a custom date range. Supports
38	 * both legacy V1 (value field / createdAt) and current V2 (movement object / readAt)
39	 * data formats. Technician-only sessions are automatically restricted to LastHour.
40	 *
41	 * URL params:
42	 * @param machineId  {string} Required (path). The machine whose bill validator data is fetched.
43	 *
44	 * Query params:
45	 * @param timePeriod  {TimePeriod} Optional. Predefined window such as 'Today', 'Yesterday',
46	 *                    '7d', '30d', 'Quarterly', 'All Time', or 'LastHour'. Defaults to '7d'.
47	 *                    Ignored when startDate + endDate are both supplied.
48	 *                    Forced to 'LastHour' for technician-only sessions.
49	 * @param startDate   {string} Optional. ISO 8601 date/datetime for custom range start.
50	 *                    Must be paired with endDate. Maps to createdAt (V1) or readAt (V2).
51	 * @param endDate     {string} Optional. ISO 8601 date/datetime for custom range end.
52	 *                    Must be paired with startDate.
53	 *
54	 * Flow:
55	 * 1. Connect to database
56	 * 2. Extract machine ID from URL path
57	 * 3. Validate machine ID
58	 * 4. Parse query parameters (timePeriod, dates)
59	 * 5. Get machine and location data
60	 * 6. Determine gaming day offset
61	 * 7. Restrict technicians to last hour
62	 * 8. Build date filter and query bills
63	 * 9. Process bills data (V1 or V2)
64	 * 10. Return processed bill validator data
65	 */
66	export async function GET(req: NextRequest) {
67	  const startTime = Date.now();
68	  const functionName = 'GET /api/bill-validator/[machineId]';
69	  const user = extractUserFromRequest(req);
70	
71	  try {
72	    // ============================================================================
73	    // STEP 1: Connect to database
74	    // ============================================================================
75	    const db = await connectDB();
76	    if (!db) {
77	      logRouteError(
78	        functionName,
79	        'GET',
80	        '/api/bill-validator/[machineId]',
81	        'Database connection failed',
82	        user
83	      );
84	      return NextResponse.json(
85	        { error: 'Database connection failed' },
86	        { status: 500 }
87	      );
88	    }
89	
90	    // ============================================================================
91	    // STEP 2: Extract machine ID from URL path
92	    // ============================================================================
93	    const url = new URL(req.url);
94	    const pathSegments = url.pathname.split('/');
95	    const machineId = pathSegments[pathSegments.length - 1];
96	
97	    // ============================================================================
98	    // STEP 3: Validate machine ID
99	    // ============================================================================
100	    if (!machineId) {
101	      logRouteError(
102	        functionName,
103	        'GET',
104	        '/api/bill-validator/[machineId]',
105	        'Machine ID is required',
106	        user
107	      );
108	      return NextResponse.json(
109	        { error: 'Machine ID is required' },
110	        { status: 400 }
111	      );
112	    }
113	
114	    // ============================================================================
115	    // STEP 4: Parse query parameters
116	    // ============================================================================
117	    const searchParams = req.nextUrl.searchParams;
118	    let timePeriod = (searchParams.get('timePeriod') as TimePeriod) || '7d';
119	    const startDate = searchParams.get('startDate');
120	    const endDate = searchParams.get('endDate');
121	
122	    // ============================================================================
123	    // STEP 5: Get machine and location data
124	    // ============================================================================
125	    let gamingLocation = null;
126	    const machine = await Machine.findOne({ _id: machineId });
127	
128	    if (machine?.gamingLocation) {
129	      gamingLocation = await GamingLocations.findOne({
130	        _id: machine.gamingLocation,
131	      });
132	    }
133	
134	    // ============================================================================
135	    // STEP 6: Technician restriction — force LastHour for technicians only
136	    // ============================================================================
137	    const { getUserFromServer: getUser } =
138	      await import('@/app/api/lib/helpers/users/users');
139	    const userPayload = await getUser();
140	    const userRoles = (userPayload?.roles as string[]) || [];
141	
142	    const userRolesLower = userRoles.map(
143	      r => r?.toLowerCase?.() ?? String(r).toLowerCase()
144	    );
145	    const isOnlyTechnician =
146	      userRolesLower.includes('technician') &&
147	      !userRolesLower.some(r =>
148	        ['admin', 'developer', 'manager', 'location admin'].includes(r)
149	      );
150	
151	    if (isOnlyTechnician) {
152	      timePeriod = 'LastHour' as TimePeriod;
153	    }
154	
155	    // ============================================================================
156	    // STEP 7: Determine gaming day offset
157	    // ============================================================================
158	    const gameDayOffset = gamingLocation?.gameDayOffset ?? 8;
159	
160	    // ============================================================================
161	    // STEP 8: Query bills with appropriate date filter
162	    // ============================================================================
163	    let bills: BillDocument[] = [];
164	    const sampleBill = await AcceptedBill.findOne({ machine: machineId });
165	
166	    if (sampleBill) {
167	      const sampleBillObj = sampleBill.toObject
168	        ? sampleBill.toObject()
169	        : sampleBill;
170	      const isV2 =
171	        sampleBillObj.movement &&
172	        typeof sampleBillObj.movement === 'object' &&
173	        sampleBillObj.value === undefined;
174	
175	      if (isV2) {
176	        const v2DateFilter = createDateFilter(
177	          startDate,
178	          endDate,
179	          timePeriod,
180	          'readAt',
181	          gameDayOffset
182	        );
183	        bills = await AcceptedBill.find({
184	          machine: machineId,
185	          ...v2DateFilter,
186	        })
187	          .sort({ readAt: -1 })
188	          .lean<BillDocument[]>();
189	      } else {
190	        const v1DateFilter = createDateFilter(
191	          startDate,
192	          endDate,
193	          timePeriod,
194	          'createdAt',
195	          gameDayOffset
196	        );
197	        bills = await AcceptedBill.find({
198	          machine: machineId,
199	          ...v1DateFilter,
200	        })
201	          .sort({ createdAt: -1 })
202	          .lean<BillDocument[]>();
203	      }
204	    }
205	
206	    // Get current balance from machine
207	    const currentBalance = machine?.billValidator?.balance || 0;
208	
209	    // Resolve location from bills if not found via machine
210	    if (!gamingLocation && bills.length > 0) {
211	      const billObj = bills[0].toObject ? bills[0].toObject() : bills[0];
212	      const billLocationId = billObj.location;
213	
214	      if (billLocationId) {
215	        gamingLocation = await GamingLocations.findOne({
216	          _id: billLocationId,
217	        });
218	      }
219	    }
220	
221	    const billValidatorOptions =
222	      gamingLocation?.billValidatorOptions || DEFAULT_BILL_VALIDATOR_OPTIONS;
223	
224	    // ============================================================================
225	    // STEP 9: Process bills data (V1 or V2)
226	    // ============================================================================
227	    const processedData = processBillsData(
228	      bills,
229	      currentBalance,
230	      billValidatorOptions as Record<string, boolean>
231	    );
232	
233	    // ============================================================================
234	    // STEP 10: Return processed bill validator data
235	    // ============================================================================
236	    const duration = Date.now() - startTime;
237	    logRouteFetch(
238	      functionName,
239	      'GET',
240	      '/api/bill-validator/[machineId]',
241	      bills.length,
242	      user,
243	      duration
244	    );
245	
246	    return NextResponse.json({
247	      success: true,
248	      data: processedData,
249	      currentBalance,
250	      totalBills: bills.length,
251	      dataVersion: processedData.version,
252	    });
253	  } catch (error) {
254	    const errorMessage =
255	      error instanceof Error ? error.message : 'Internal server error';
256	    logRouteError(
257	      functionName,
258	      'GET',
259	      '/api/bill-validator/[machineId]',
260	      errorMessage,
261	      user
262	    );
263	    return NextResponse.json({ error: errorMessage }, { status: 500 });
264	  }
265	}
