1	/**
2	 * Analytics Charts API Route
3	 *
4	 * This route handles fetching chart data for analytics visualization.
5	 *
6	 * @module app/api/analytics/charts/route
7	 */
8	
9	import { getChartsData } from '@/app/api/lib/helpers/reports/analytics';
10	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
11	import type { CurrencyCode } from '@/shared/types/currency';
12	import { NextRequest, NextResponse } from 'next/server';
13	import {
14	  logRouteFetch,
15	  logRouteError,
16	  extractUserFromRequest,
17	} from '@/app/api/lib/utils/routeLogger';
18	
19	/**
20	 * GET /api/analytics/charts
21	 *
22	 * Returns time-series chart data for revenue and financial metrics. Used by the Analytics dashboard charts section.
23	 *
24	 * Query params:
25	 * @param licencee  {string}              Required. Scopes results to this licencee.
26	 * @param period    {'last7days'|'last30days'} Optional. Time window for the chart data. Defaults to 'last30days'.
27	 * @param currency  {CurrencyCode}        Optional. Display currency for converted values. Defaults to 'USD'.
28	 */
29	export async function GET(request: NextRequest) {
30	  const startTime = Date.now();
31	  const functionName = 'GET /api/analytics/charts';
32	  const user = extractUserFromRequest(request);
33	
34	  return withApiAuth(request, async () => {
35	    const { searchParams } = new URL(request.url);
36	    const licencee = searchParams.get('licencee');
37	    const period =
38	      (searchParams.get('period') as 'last7days' | 'last30days') ||
39	      'last30days';
40	    const displayCurrency =
41	      (searchParams.get('currency') as CurrencyCode) || 'USD';
42	
43	    if (!licencee) {
44	      logRouteError(
45	        functionName,
46	        'GET',
47	        '/api/analytics/charts',
48	        'Licencee is required',
49	        user
50	      );
51	      return NextResponse.json(
52	        { message: 'Licencee is required' },
53	        { status: 400 }
54	      );
55	    }
56	
57	    const chartsData = await getChartsData(licencee, period, displayCurrency);
58	    const duration = Date.now() - startTime;
59	    logRouteFetch(
60	      functionName,
61	      'GET',
62	      '/api/analytics/charts',
63	      1,
64	      user,
65	      duration
66	    );
67	    return NextResponse.json(chartsData);
68	  });
69	}
