1	/**
2	 * Analytics Dashboard API Route
3	 *
4	 * This route handles fetching dashboard analytics data for a specific licencee.
5	 *
6	 * @module app/api/analytics/dashboard/route
7	 */
8	
9	import { getDashboardAnalytics } from '@/app/api/lib/helpers/reports/analytics';
10	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
11	import { shouldApplyCurrencyConversion } from '@/lib/helpers/currencyConversion';
12	import { convertFromUSD } from '@/lib/helpers/rates';
13	import type { CurrencyCode } from '@/shared/types/currency';
14	import { NextRequest, NextResponse } from 'next/server';
15	import {
16	  logRouteFetch,
17	  logRouteError,
18	  extractUserFromRequest,
19	} from '@/app/api/lib/utils/routeLogger';
20	
21	/**
22	 * GET /api/analytics/dashboard
23	 *
24	 * Returns aggregated financial metrics for a licencee's dashboard summary card.
25	 * Called on dashboard page load and whenever the licencee selector changes.
26	 *
27	 * Query params:
28	 * @param licencee  {string} Required. The licencee ID to scope all metric aggregation to.
29	 *                           Drives totalDrop, totalCancelledCredits, and totalGross calculations.
30	 * @param currency  {CurrencyCode} Optional. Target display currency (e.g. 'TTD', 'USD').
31	 *                                 When the licencee has currency conversion enabled, financial
32	 *                                 fields are converted from USD to this currency before returning.
33	 *                                 Defaults to 'USD' (no conversion applied).
34	 */
35	export async function GET(request: NextRequest) {
36	  const startTime = Date.now();
37	  const functionName = 'GET /api/analytics/dashboard';
38	  const user = extractUserFromRequest(request);
39	
40	  return withApiAuth(request, async () => {
41	    const { searchParams } = new URL(request.url);
42	    const licencee = searchParams.get('licencee');
43	    const displayCurrency =
44	      (searchParams.get('currency') as CurrencyCode) || 'USD';
45	
46	    if (!licencee) {
47	      logRouteError(
48	        functionName,
49	        'GET',
50	        '/api/analytics/dashboard',
51	        'Licencee is required',
52	        user
53	      );
54	      return NextResponse.json(
55	        { message: 'Licencee is required' },
56	        { status: 400 }
57	      );
58	    }
59	
60	    const globalStats = await getDashboardAnalytics(licencee);
61	
62	    let convertedStats = globalStats;
63	    if (shouldApplyCurrencyConversion(licencee)) {
64	      const financialFields = [
65	        'totalDrop',
66	        'totalCancelledCredits',
67	        'totalGross',
68	      ];
69	      convertedStats = { ...globalStats };
70	
71	      financialFields.forEach(field => {
72	        const value = (globalStats as Record<string, unknown>)[field];
73	        if (typeof value === 'number') {
74	          (convertedStats as Record<string, unknown>)[field] = convertFromUSD(
75	            value,
76	            displayCurrency
77	          );
78	        }
79	      });
80	    }
81	
82	    const duration = Date.now() - startTime;
83	    logRouteFetch(
84	      functionName,
85	      'GET',
86	      '/api/analytics/dashboard',
87	      1,
88	      user,
89	      duration
90	    );
91	
92	    return NextResponse.json({
93	      globalStats: convertedStats,
94	      currency: displayCurrency,
95	      converted: shouldApplyCurrencyConversion(licencee),
96	    });
97	  });
98	}
