30	  const startTime = Date.now();
31	  const functionName = 'GET /api/analytics/hourly-revenue';
32	  const user = extractUserFromRequest(request);
33	
34	  return withApiAuth(request, async () => {
35	    const { searchParams } = new URL(request.url);
36	    const locationId = searchParams.get('locationId');
37	    const timePeriod = searchParams.get('timePeriod') || '24h';
38	    const startDate = searchParams.get('startDate');
39	    const endDate = searchParams.get('endDate');
40	
41	    if (!locationId) {
42	      logRouteError(
43	        functionName,
44	        'GET',
45	        '/api/analytics/hourly-revenue',
46	        'Location ID is required',
47	        user
48	      );
49	      return NextResponse.json(
50	        { error: 'Location ID is required' },
51	        { status: 400 }
52	      );
53	    }
54	
55	    const hourlyRevenue = await getHourlyRevenue(
56	      locationId,
57	      timePeriod,
58	      startDate,
59	      endDate
60	    );
61	
62	    const duration = Date.now() - startTime;
63	    logRouteFetch(
64	      functionName,
65	      'GET',
66	      '/api/analytics/hourly-revenue',
67	      1,
68	      user,
69	      duration
70	    );
71	
72	    return NextResponse.json(hourlyRevenue);
73	  });
74	}
