1	/**
2	 * Analytics Jackpot Trends API Route
3	 *
4	 * This route handles fetching jackpot trends data over time.
5	 *
6	 * @module app/api/analytics/jackpot-trends/route
7	 */
8	
9	import { getJackpotTrends } from '@/app/api/lib/helpers/trends/general';
10	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
11	import { TimePeriod } from '@/shared/types';
12	import { NextRequest, NextResponse } from 'next/server';
13	import {
14	  logRouteFetch,
15	  extractUserFromRequest,
16	} from '@/app/api/lib/utils/routeLogger';
17	
18	/**
19	 * GET /api/analytics/jackpot-trends
20	 *
21	 * Returns jackpot payout trend data aggregated over the requested period. Used by the Analytics jackpot trends chart.
22	 *
23	 * Query params:
24	 * @param timePeriod  {TimePeriod} Optional. 'Today'|'Yesterday'|'7d'|'30d'|'Custom'. Defaults to 'Today'.
25	 * @param licencee    {string}     Optional. Scopes results to this licencee.
26	 * @param locationIds {string}     Optional. Comma-separated location IDs to filter results.
27	 */
28	export async function GET(req: NextRequest) {
29	  const startTime = Date.now();
30	  const functionName = 'GET /api/analytics/jackpot-trends';
31	  const user = extractUserFromRequest(req);
32	
33	  return withApiAuth(req, async () => {
34	    const { searchParams } = new URL(req.url);
35	    const timePeriod =
36	      (searchParams.get('timePeriod') as TimePeriod) || 'Today';
37	    const licencee = searchParams.get('licencee');
38	    const locationIds = searchParams.get('locationIds');
39	
40	    const jackpotTrends = await getJackpotTrends(
41	      timePeriod,
42	      licencee,
43	      locationIds
44	    );
45	
46	    const duration = Date.now() - startTime;
47	    logRouteFetch(
48	      functionName,
49	      'GET',
50	      '/api/analytics/jackpot-trends',
51	      1,
52	      user,
53	      duration
54	    );
55	
56	    return NextResponse.json({
57	      success: true,
58	      data: jackpotTrends,
59	      timePeriod,
60	      locationIds: locationIds ? locationIds.split(',') : null,
61	    });
62	  });
63	}
