1	/**
2	 * Analytics Location Trends API Route
3	 *
4	 * This route handles fetching location trends data over time.
5	 * It supports:
6	 * - Filtering by location IDs
7	 * - Time period filtering (Today, Yesterday, 7d, 30d, Custom)
8	 * - Licencee-based filtering
9	 * - Gaming day offset calculations
10	 * - Hourly or daily aggregation based on time period
11	 * - Currency conversion for multi-licencee views
12	 *
13	 * @module app/api/analytics/location-trends/route
14	 */
15	
16	import { getLocationTrends } from '@/app/api/lib/helpers/trends/locations';
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import { TimePeriod } from '@/shared/types';
19	import type { CurrencyCode } from '@/shared/types/currency';
20	import { NextRequest, NextResponse } from 'next/server';
21	import {
22	  logRouteFetch,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	
27	/**
28	 * GET /api/analytics/location-trends
29	 *
30	 * Returns financial and gaming trend data for one or more locations over time. Used by the location analytics trends page.
31	 *
32	 * Query params:
33	 * @param locationIds     {string}                                   Required. Comma-separated location IDs to include.
34	 * @param timePeriod      {TimePeriod}                               Optional. 'Today'|'Yesterday'|'7d'|'30d'|'Custom'. Defaults to 'Today'.
35	 * @param licencee        {string}                                   Optional. Scopes results to this licencee.
36	 * @param startDate       {string}                                   Optional. ISO datetime string for the start of a custom range.
37	 * @param endDate         {string}                                   Optional. ISO datetime string for the end of a custom range.
38	 * @param currency        {CurrencyCode}                             Optional. Display currency for converted values. Defaults to 'USD'.
39	 * @param granularity     {'hourly'|'daily'|'weekly'|'monthly'}      Optional. Aggregation granularity. Defaults to 'daily'.
40	 * @param status          {'Online'|'Offline'|'All'}                 Optional. Filters machines by online status.
41	 * @param gameType        {string}                                   Optional. Filters machines by game type.
42	 * @param search          {string}                                   Optional. Text search applied to machine/cabinet names.
43	 * @param includeArchived {string}                                   Optional. Pass 'true' to include archived machines.
44	 *
45	 * Flow:
46	 * 1. Connect to database
47	 * 2. Parse and validate request parameters (locationIds, timePeriod, licencee, startDate, endDate, currency)
48	 * 3. Execute the core location trends fetching logic via `getLocationTrends` helper
49	 * 4. Return location trends data
50	 */
51	export async function GET(req: NextRequest) {
52	  const startTime = Date.now();
53	  const functionName = 'GET /api/analytics/location-trends';
54	  const user = extractUserFromRequest(req);
55	
56	  try {
57	    // ============================================================================
58	    // STEP 1: Connect to database
59	    // ============================================================================
60	    const db = await connectDB();
61	    if (!db) {
62	      logRouteError(
63	        functionName,
64	        'GET',
65	        '/api/analytics/location-trends',
66	        'Database connection not established',
67	        user
68	      );
69	      return NextResponse.json(
70	        { error: 'Database connection not established' },
71	        { status: 500 }
72	      );
73	    }
74	
75	    // ============================================================================
76	    // STEP 2: Parse and validate request parameters
77	    // Example: GET /api/analytics/location-trends?locationIds=6801f2a3b4c5d6e7f8901234,6802f3b4c5d6e7f890123456&licencee=9a5db2cb29ffd2d962fd1d91&currency=TTD&timePeriod=Yesterday&granularity=hourly
78	    // ============================================================================
79	    const { searchParams } = new URL(req.url);
80	    const locationIds = searchParams.get('locationIds');
81	    const timePeriod =
82	      (searchParams.get('timePeriod') as TimePeriod) || 'Today';
83	    const licencee = searchParams.get('licencee');
84	    const startDateParam = searchParams.get('startDate');
85	    const endDateParam = searchParams.get('endDate');
86	    const displayCurrency =
87	      (searchParams.get('currency') as CurrencyCode) || 'USD';
88	    const granularity = searchParams.get('granularity') as
89	      | 'hourly'
90	      | 'minute'
91	      | 'daily'
92	      | 'weekly'
93	      | 'monthly';
94	    const status = searchParams.get('status') as
95	      | 'Online'
96	      | 'Offline'
97	      | 'All'
98	      | null;
99	    const gameType = searchParams.get('gameType');
