1	/**
2	 * Bill Validator API Route
3	 *
4	 * This route handles fetching bill validator data for a specific machine.
5	 * It supports:
6	 * - V1 and V2 data format handling
7	 * - Gaming day offset calculations
8	 * - Time period filtering
9	 * - Custom date range filtering
10	 * - Bill denomination filtering based on location settings
11	 *
12	 * @module app/api/bill-validator/[machineId]/route
13	 */
14	
15	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
16	import { AcceptedBill } from '@/app/api/lib/models/acceptedBills';
17	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
18	import { Machine } from '@/app/api/lib/models/machines';
19	import type { TimePeriod } from '@/shared/types/common';
20	import {
21	  processBillsData,
22	  createDateFilter,
23	  DEFAULT_BILL_VALIDATOR_OPTIONS,
24	  type BillDocument,
25	} from '@/app/api/lib/helpers/billValidator/validatorOperations';
26	import {
27	  logRouteFetch,
28	  logRouteError,
29	  extractUserFromRequest,
30	} from '@/app/api/lib/utils/routeLogger';
31	import { NextRequest, NextResponse } from 'next/server';
32	
33	/**
34	 * GET /api/bill-validator/[machineId]
35	 *
36	 * Returns denomination-level bill validator data (counts, subtotals, and totals)
37	 * for a single machine, filtered by time period or a custom date range. Supports
38	 * both legacy V1 (value field / createdAt) and current V2 (movement object / readAt)
39	 * data formats. Technician-only sessions are automatically restricted to LastHour.
40	 *
41	 * URL params:
42	 * @param machineId  {string} Required (path). The machine whose bill validator data is fetched.
43	 *
44	 * Query params:
45	 * @param timePeriod  {TimePeriod} Optional. Predefined window such as 'Today', 'Yesterday',
46	 *                    '7d', '30d', 'Quarterly', 'All Time', or 'LastHour'. Defaults to '7d'.
47	 *                    Ignored when startDate + endDate are both supplied.
48	 *                    Forced to 'LastHour' for technician-only sessions.
49	 * @param startDate   {string} Optional. ISO 8601 date/datetime for custom range start.
50	 *                    Must be paired with endDate. Maps to createdAt (V1) or readAt (V2).
51	 * @param endDate     {string} Optional. ISO 8601 date/datetime for custom range end.
52	 *                    Must be paired with startDate.
53	 *
54	 * Flow:
55	 * 1. Connect to database
56	 * 2. Extract machine ID from URL path
57	 * 3. Validate machine ID
58	 * 4. Parse query parameters (timePeriod, dates)
59	 * 5. Get machine and location data
60	 * 6. Determine gaming day offset
61	 * 7. Restrict technicians to last hour
62	 * 8. Build date filter and query bills
63	 * 9. Process bills data (V1 or V2)
64	 * 10. Return processed bill validator data
65	 */
66	export async function GET(req: NextRequest) {
67	  const startTime = Date.now();
68	  const functionName = 'GET /api/bill-validator/[machineId]';
69	  const user = extractUserFromRequest(req);
70	
71	  return withApiAuth(req, async ({ userRoles }) => {
72	    try {
73	      // ============================================================================
74	      // STEP 1: Extract machine ID from URL path
75	      // ============================================================================
76	      const url = new URL(req.url);
77	      const pathSegments = url.pathname.split('/');
78	      const machineId = pathSegments[pathSegments.length - 1];
79	
80	      // ============================================================================
81	      // STEP 2: Validate machine ID
82	      // ============================================================================
83	      if (!machineId) {
84	        logRouteError(
85	          functionName,
86	          'GET',
87	          '/api/bill-validator/[machineId]',
88	          'Machine ID is required',
89	          user
90	        );
91	        return NextResponse.json(
92	          { error: 'Machine ID is required' },
93	          { status: 400 }
94	        );
95	      }
96	
97	      // ============================================================================
98	      // STEP 3: Parse query parameters
99	      // ============================================================================
100	      const searchParams = req.nextUrl.searchParams;
101	      let timePeriod = (searchParams.get('timePeriod') as TimePeriod) || '7d';
102	      const startDate = searchParams.get('startDate');
103	      const endDate = searchParams.get('endDate');
104	
105	      // ============================================================================
106	      // STEP 4: Get machine and location data
107	      // ============================================================================
108	      let gamingLocation = null;
109	      const machine = await Machine.findOne({ _id: machineId });
110	
111	      if (machine?.gamingLocation) {
112	        gamingLocation = await GamingLocations.findOne({
113	          _id: machine.gamingLocation,
114	        });
115	      }
116	
117	      // ============================================================================
118	      // STEP 5: Technician restriction — force LastHour for technicians only
119	      // ============================================================================
120	      const userRolesLower = userRoles.map(
121	        (role: string) => role?.toLowerCase?.() ?? String(role).toLowerCase()
122	      );
123	      const isOnlyTechnician =
124	        userRolesLower.includes('technician') &&
125	        !userRolesLower.some((role: string) =>
126	          ['admin', 'developer', 'manager', 'location admin'].includes(role)
127	        );
128	
129	      if (isOnlyTechnician) {
130	        timePeriod = 'LastHour' as TimePeriod;
131	      }
132	
133	      // ============================================================================
134	      // STEP 6: Determine gaming day offset
135	      // ============================================================================
136	      const gameDayOffset = gamingLocation?.gameDayOffset ?? 8;
137	
138	      // ============================================================================
139	      // STEP 7: Query bills with appropriate date filter
140	      // ============================================================================
141	      let bills: BillDocument[] = [];
142	      const sampleBill = await AcceptedBill.findOne({ machine: machineId });
143	
144	      if (sampleBill) {
145	        const sampleBillObj = sampleBill.toObject
146	          ? sampleBill.toObject()
147	          : sampleBill;
148	        const isV2 =
149	          sampleBillObj.movement &&
150	          typeof sampleBillObj.movement === 'object' &&
151	          sampleBillObj.value === undefined;
152	
153	        if (isV2) {
154	          const v2DateFilter = createDateFilter(
155	            startDate,
156	            endDate,
157	            timePeriod,
158	            'readAt',
159	            gameDayOffset
160	          );
161	          bills = await AcceptedBill.find({
162	            machine: machineId,
163	            ...v2DateFilter,
164	          })
165	            .sort({ readAt: -1 })
166	            .lean<BillDocument[]>();
167	        } else {
168	          const v1DateFilter = createDateFilter(
169	            startDate,
170	            endDate,
171	            timePeriod,
172	            'createdAt',
173	            gameDayOffset
174	          );
175	          bills = await AcceptedBill.find({
176	            machine: machineId,
177	            ...v1DateFilter,
178	          })
179	            .sort({ createdAt: -1 })
180	            .lean<BillDocument[]>();
181	        }
182	      }
183	
184	      // Get current balance from machine
185	      const currentBalance = machine?.billValidator?.balance || 0;
186	
187	      // Resolve location from bills if not found via machine
188	      if (!gamingLocation && bills.length > 0) {
189	        const billObj = bills[0].toObject ? bills[0].toObject() : bills[0];
190	        const billLocationId = billObj.location;
191	
192	        if (billLocationId) {
193	          gamingLocation = await GamingLocations.findOne({
194	            _id: billLocationId,
195	          });
196	        }
197	      }
198	
199	      const billValidatorOptions =
200	        gamingLocation?.billValidatorOptions || DEFAULT_BILL_VALIDATOR_OPTIONS;
201	
202	      // ============================================================================
203	      // STEP 8: Process bills data (V1 or V2)
204	      // ============================================================================
205	      const processedData = processBillsData(
206	        bills,
207	        currentBalance,
208	        billValidatorOptions as Record<string, boolean>
209	      );
210	
211	      // ============================================================================
212	      // STEP 9: Return processed bill validator data
213	      // ============================================================================
214	      const duration = Date.now() - startTime;
215	      logRouteFetch(
216	        functionName,
217	        'GET',
218	        '/api/bill-validator/[machineId]',
219	        bills.length,
220	        user,
221	        duration
222	      );
223	
224	      if (duration > 1000) {
225	        console.warn(`[${functionName}] Slow response — ${duration}ms`);
226	      }
227	
228	      return NextResponse.json({
229	        success: true,
230	        data: processedData,
231	        currentBalance,
232	        totalBills: bills.length,
233	        dataVersion: processedData.version,
234	      });
235	    } catch (e) {
236	      const errorMessage =
237	        e instanceof Error ? e.message : 'Internal server error';
238	      logRouteError(
239	        functionName,
240	        'GET',
241	        '/api/bill-validator/[machineId]',
242	        errorMessage,
243	        user
244	      );
245	      return NextResponse.json({ error: errorMessage }, { status: 500 });
246	    }
247	  });
248	}
